import{_ as t,o,c as a,ag as s}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"术语表","description":"","frontmatter":{},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md"}'),l={name:"glossary.md"};function n(e,r,i,g,c,h){return o(),a("div",null,[...r[0]||(r[0]=[s('<h1 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h1><h2 id="postgresql-基础" tabindex="-1">PostgreSQL 基础 <a class="header-anchor" href="#postgresql-基础" aria-label="Permalink to &quot;PostgreSQL 基础&quot;">​</a></h2><ul><li><strong>Database</strong>：一个相对独立的数据世界。</li><li><strong>Schema</strong>：数据库内部的命名空间。</li><li><strong>Table</strong>：业务对象、事件或关系的数据化表达。</li><li><strong>Row</strong>：一条事实记录。</li><li><strong>Column</strong>：事实的属性。</li><li><strong>Primary Key</strong>：解决记录身份问题。</li><li><strong>Foreign Key</strong>：解决表之间关系问题。</li><li><strong>Transaction</strong>：让多步修改表现得像一个可靠动作。</li></ul><h2 id="数据平台" tabindex="-1">数据平台 <a class="header-anchor" href="#数据平台" aria-label="Permalink to &quot;数据平台&quot;">​</a></h2><ul><li><strong>OLTP</strong>：面向业务交易，高频小事务、低延迟和强一致优先。</li><li><strong>OLAP</strong>：面向数据分析，大范围扫描、聚合和吞吐优先。</li><li><strong>ETL / ELT</strong>：数据抽取、转换、装载的链路模式。</li><li><strong>CDC</strong>：捕获数据库变更并形成持续数据流。</li><li><strong>Lakehouse</strong>：用表格式把对象存储中的文件组织成可管理的分析表。</li></ul><h2 id="ai-数据系统" tabindex="-1">AI 数据系统 <a class="header-anchor" href="#ai-数据系统" aria-label="Permalink to &quot;AI 数据系统&quot;">​</a></h2><ul><li><strong>Embedding</strong>：把文本、图片、代码等对象转换成向量。</li><li><strong>Vector Search</strong>：基于向量相似度检索内容。</li><li><strong>GraphRAG</strong>：结合图关系和检索增强生成的 AI 应用模式。</li><li><strong>Data Governance</strong>：质量、元数据、血缘、权限、指标和知识治理的综合体系。</li></ul>',7)])])}const _=t(l,[["render",n]]);export{u as __pageData,_ as default};
